// ---- launch, async, and Dispatchers ----

// ---- launch (fire and forget) ----
class LaunchViewModel : ViewModel() {
    private val _log = MutableStateFlow<List<String>>(emptyList())
    val log: StateFlow<List<String>> = _log.asStateFlow()

    fun doLaunchWork() {
        viewModelScope.launch {
            addLog("Started")
            delay(1000)
            addLog("Finished")
        }
        addLog("Function returned")
    }

    private fun addLog(msg: String) {
        _log.update { it + msg }
    }
}

// ---- async (returns a result) ----
class AsyncViewModel : ViewModel() {
    private val _result = MutableStateFlow<String?>(null)
    val result: StateFlow<String?> = _result.asStateFlow()

    fun doAsyncWork() {
        viewModelScope.launch {
            val deferred = async {
                // Heavy computation
                delay(2000)
                "Result from async"
            }

            val result = deferred.await()
            _result.value = result
        }
    }

    // ---- Multiple async calls ----
    fun doMultipleAsync() {
        viewModelScope.launch {
            val deferred1 = async { fetchData(1) }
            val deferred2 = async { fetchData(2) }
            val deferred3 = async { fetchData(3) }

            val results = listOf(
                deferred1.await(),
                deferred2.await(),
                deferred3.await()
            )
            _result.value = results.joinToString(", ")
        }
    }

    private suspend fun fetchData(id: Int): String {
        delay(1000)
        return "Data from $id"
    }
}

// ---- Dispatchers ----
class DispatcherViewModel : ViewModel() {
    private val _state = MutableStateFlow("Idle")
    val state: StateFlow<String> = _state.asStateFlow()

    fun demonstrateDispatchers() {
        viewModelScope.launch {
            _state.value = "Starting on ${Thread.currentThread().name}"

            // ---- Main dispatcher ----
            // UI updates

            // ---- IO dispatcher ----
            withContext(Dispatchers.IO) {
                _state.value = "IO work on ${Thread.currentThread().name}"
                delay(1000)
            }

            // ---- Default dispatcher ----
            withContext(Dispatchers.Default) {
                _state.value = "CPU work on ${Thread.currentThread().name}"
                val result = heavyComputation()
                _state.value = "Computation result: $result"
            }

            // ---- Back to main ----
            _state.value = "Finished on ${Thread.currentThread().name}"
        }
    }

    private suspend fun heavyComputation(): Int {
        return (1..1000000).sum()
    }
}

// ---- Combining launch and async ----
class CombinedViewModel : ViewModel() {
    private val _state = MutableStateFlow("")
    val state: StateFlow<String> = _state.asStateFlow()

    fun combinedWork() {
        viewModelScope.launch {
            // ---- Launch a coroutine ----
            val job = launch {
                _state.value = "Background work started"
                delay(1000)
                _state.value = "Background work done"
            }

            // ---- Async for result ----
            val result = async {
                delay(500)
                "Async result"
            }

            job.join()
            _state.value = "${result.await()} completed"
        }
    }
}

// ---- UI for dispatchers ----
@Composable
fun DispatcherScreen() {
    val viewModel: DispatcherViewModel = viewModel()
    val state by viewModel.state.collectAsState()

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Text(
            text = state,
            style = MaterialTheme.typography.bodyLarge
        )

        Button(
            onClick = { viewModel.demonstrateDispatchers() },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Run Dispatchers Demo")
        }
    }
}

