package com.example.async

import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.compose.viewModel
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

class AsyncViewModel : ViewModel() {
    private val _result = MutableStateFlow("Waiting...")
    val result: StateFlow<String> = _result.asStateFlow()

    fun fetchData() {
        viewModelScope.launch {
            _result.value = "Loading..."

            val deferred1 = async { fetchData(1) }
            val deferred2 = async { fetchData(2) }

            val results = awaitAll(deferred1, deferred2)
            _result.value = results.joinToString(", ")
        }
    }

    private suspend fun fetchData(id: Int): String {
        delay(1000)
        return "Data from $id"
    }
}

@Composable
fun AsyncApp() {
    val viewModel: AsyncViewModel = viewModel()
    val result by viewModel.result.collectAsState()

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Text(
            text = result,
            style = MaterialTheme.typography.headlineMedium
        )

        Button(
            onClick = { viewModel.fetchData() },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Fetch Data")
        }
    }
}
